#include <bits/stdc++.h>
using namespace std;
typedef __int128 ll;
const int N=1e6+6;
int n,a[N],b[N],m;
ll c[N],ans;
void write(ll x){
    if(x>9)
        write(x/10);
    putchar(x%10+'0');
}
ll read()
{
	ll x=0,f=1;
	char ch=getchar();
	while(ch<'0'||ch>'9')
	{
		if(ch=='-')f=-1;
		ch=getchar();
	}
	while(ch>='0'&&ch<='9')
	{
		x=(x<<3)+(x<<1)+ch-'0';
		ch=getchar();
	}
	return x*f;
}
ll lowbit(ll x){
    return x&(-x);
}
ll Sum(ll x){
    if(!x)
        return 0;
    return c[x]+Sum(x-lowbit(x));
}
void Add(int x,int y){
    if(x>m)
        return;
    c[x]+=y;
    Add(x+lowbit(x),y);
}
int main(){
    n=read();
    for(int i=1;i<=n;i++)
        a[i]=read(),b[i]=a[i],m=max(m,a[i]);
    sort(b+1,b+n+1);
    int tot=unique(b+1,b+n+1)-b-1;
    for(ll i=n;i;i--){
        int t=lower_bound(b+1,b+tot+1,a[i])-b;
        Add(t,n-i+1);
        ans+=i*Sum(i-1);
    }
    write(ans);
    return 0;
}
